/**
 * Replace the value of the key in the object with the value returned by the function
 * @param obj - The object to replace the value of the key
 * @param targetKey - The key to replace the value of. If null, replace all keys.
 * @param func - The function to return the value of the key
 * @returns The object with the value of the key replaced by the value returned by the function
 */
static replaceValueByKey<T, U>(
  obj: T,
  targetKey: string | null,
  func: (value: string) => U,
): T {
  // nullやundefinedの場合はそのまま返す
  if (obj === null || obj === undefined) {
    return obj;
  }

  // プリミティブ値の場合はそのまま返す
  if (typeof obj !== 'object') {
    return obj;
  }

  // 配列の場合
  if (Array.isArray(obj)) {
    return obj.map((item) =>
      DataUtil.replaceValueByKey(item, targetKey, func),
    ) as T;
  }

  // オブジェクトの場合
  const result: any = {}; // eslint-disable-line @typescript-eslint/no-explicit-any
  for (const key in obj) {
    if (Object.prototype.hasOwnProperty.call(obj, key)) {
      if (
        (targetKey === null || key === targetKey) &&
        typeof obj[key] === 'string'
      ) {
        // ターゲットキーの場合は元の値を関数に渡す
        result[key] = func(obj[key]);
      } else {
        // それ以外は再帰的に処理
        result[key] = DataUtil.replaceValueByKey(obj[key], targetKey, func);
      }
    }
  }
  return result;
}

