// Convert meters to inches
static meterToInch(n?: number | null): number | null {
  if (_.isNil(n)) {
    return null;
  }
  return n * 39.3701;
}

static inchToMeter(n?: number | null): number | null {
  if (_.isNil(n)) {
    return null;
  }
  return n / 39.3701;
}

// Convert km/h to mph
static kmhToMph(n?: number | null): number | null {
  if (_.isNil(n)) {
    return null;
  }
  const kmToMileRatio = 1.60934;
  return n / kmToMileRatio;
}

static mphToKmh(n?: number | null): number | null {
  if (_.isNil(n)) {
    return null;
  }
  const mileToKmRatio = 1.60934;
  return n * mileToKmRatio;
}

static round1(n: number): number {
  return Math.round(n * 10) / 10;
}

private static convertInchesRangeToCentimeters(value: string): string {
  const inchRangePattern =
    /([+-]?)(\d+(?:\.\d+)?)([\s\u3000]*[–—-][\s\u3000]*)([+-]?)(\d+(?:\.\d+)?)[\s\u3000]*(?:inch(?:es)?|in\.?|"|″|インチ)/gi;

  return value.replace(
    inchRangePattern,
    (match, fromSign, fromNum, separator, toSign, toNum) => {
      const fromValue = parseFloat(`${fromSign}${fromNum}`);
      const toValue = parseFloat(`${toSign}${toNum}`);

      if (Number.isNaN(fromValue) || Number.isNaN(toValue)) {
        return match;
      }

      const fromMeters = DataUtil.inchToMeter(fromValue);
      const toMeters = DataUtil.inchToMeter(toValue);

      if (_.isNil(fromMeters) || _.isNil(toMeters)) {
        return match;
      }

      const fromCm = fromMeters * 100;
      const toCm = toMeters * 100;

      const formattedFrom = DataUtil.applyExplicitPlus(
        DataUtil.formatWithOneDecimal(fromCm),
        fromSign,
      );
      const formattedTo = DataUtil.applyExplicitPlus(
        DataUtil.formatWithOneDecimal(toCm),
        toSign,
      );

      return `${formattedFrom}${separator}${formattedTo}cm`;
    },
  );
}

private static convertInchesToCentimeters(value: string): string {
  const inchPattern =
    /([+-]?)(\d+(?:\.\d+)?)[\s\u3000]*(?:inch(?:es)?|in\.?|"|″|インチ)/gi;

  return value.replace(inchPattern, (match, sign, num) => {
    const inches = parseFloat(`${sign}${num}`);
    if (Number.isNaN(inches)) {
      return match;
    }

    const meters = DataUtil.inchToMeter(inches);
    if (_.isNil(meters)) {
      return match;
    }

    const centimeters = meters * 100;
    const formatted = DataUtil.applyExplicitPlus(
      DataUtil.formatWithOneDecimal(centimeters),
      sign,
    );
    return `${formatted}cm`;
  });
}

private static convertMphToKmh(value: string): string {
  const mphPattern =
    /([+-]?)(\d+(?:\.\d+)?)[\s\u3000]*(?:mph|miles\s*per\s*hour|mile\/h|miles\/hour|マイル(?:\/|毎)時)/gi;

  return value.replace(mphPattern, (match, sign, num) => {
    const mph = parseFloat(`${sign}${num}`);
    if (Number.isNaN(mph)) {
      return match;
    }

    const kmh = DataUtil.mphToKmh(mph);
    if (_.isNil(kmh)) {
      return match;
    }

    const formatted = DataUtil.applyExplicitPlus(
      DataUtil.formatWithOneDecimal(kmh),
      sign,
    );
    return `${formatted}km/h`;
  });
}

private static convertMphRangeToKmh(value: string): string {
  const mphRangePattern =
    /([+-]?)(\d+(?:\.\d+)?)([\s\u3000]*[–—-][\s\u3000]*)([+-]?)(\d+(?:\.\d+)?)[\s\u3000]*(?:mph|miles\s*per\s*hour|mile\/h|miles\/hour|マイル(?:\/|毎)時)/gi;

  return value.replace(
    mphRangePattern,
    (match, fromSign, fromNum, separator, toSign, toNum) => {
      const fromValue = parseFloat(`${fromSign}${fromNum}`);
      const toValue = parseFloat(`${toSign}${toNum}`);

      if (Number.isNaN(fromValue) || Number.isNaN(toValue)) {
        return match;
      }

      const fromKmh = DataUtil.mphToKmh(fromValue);
      const toKmh = DataUtil.mphToKmh(toValue);

      if (_.isNil(fromKmh) || _.isNil(toKmh)) {
        return match;
      }

      const formattedFrom = DataUtil.applyExplicitPlus(
        DataUtil.formatWithOneDecimal(fromKmh),
        fromSign,
      );
      const formattedTo = DataUtil.applyExplicitPlus(
        DataUtil.formatWithOneDecimal(toKmh),
        toSign,
      );

      return `${formattedFrom}${separator}${formattedTo}km/h`;
    },
  );
}

private static formatWithOneDecimal(value: number): string {
  const rounded = Math.round(value * 10) / 10;
  const normalized = Object.is(rounded, -0) ? 0 : rounded;
  return normalized.toFixed(1);
}

private static applyExplicitPlus(
  formatted: string,
  originalSign: string,
): string {
  if (originalSign === '+' && !formatted.startsWith('-')) {
    return `+${formatted}`;
  }
  return formatted;
}
